import pandas as pd
from sklearn.preprocessing import LabelEncoder

def task_func(df, dct, columns=None):
    if not isinstance(df, pd.DataFrame):
        raise ValueError("The input df must be a DataFrame.")

    preprocessed_df = df.copy()

    if columns is None:
        columns = list(preprocessed_df)

    numerical_columns = [col for col in columns if preprocessed_df[col].dtype != object]
    categorical_columns = [col for col in columns if preprocessed_df[col].dtype == object]

    if numerical_columns:
        for col in numerical_columns:
            mean = preprocessed_df[col].mean()
            std = preprocessed_df[col].std()
            preprocessed_df[col] = (preprocessed_df[col] - mean) / std

    if categorical_columns:
        le = LabelEncoder()
        for col in categorical_columns:
            preprocessed_df[col] = le.fit_transform(preprocessed_df[col])

    return preprocessed_df
